export const STYLE_CSS = "* { box-sizing: border-box; }\nbody { font-family: system-ui, -apple-system, \"Segoe UI\", sans-serif; margin: 0; background: #1a1d23; color: #e4e6eb; font-size: 13px; height: 100vh; }\n#root { height: 100vh; display: flex; flex-direction: column; }\n.header { display: flex; gap: 1rem; align-items: baseline; flex-wrap: wrap; padding: 0.7rem 1.2rem; border-bottom: 1px solid #2a2e37; background: #21252e; }\nh1 { font-size: 1.1rem; margin: 0; }\n.hint { color: #8b919e; font-size: 0.82rem; }\nbutton { padding: 0.3rem 0.8rem; background: #2a2e37; color: #e4e6eb; border: 1px solid #3a3f4a; border-radius: 4px; cursor: pointer; font-size: 0.82rem; }\nbutton:hover { background: #323843; }\n.layout { flex: 1; display: flex; min-height: 0; }\n.nav-users, .nav-projects { border-right: 1px solid #2a2e37; overflow-y: auto; display: flex; flex-direction: column; }\n.nav-users { width: 180px; }\n.nav-projects { width: 220px; }\n.nav-head { padding: 0.6rem 0.8rem; border-bottom: 1px solid #2a2e37; color: #8b919e; font-size: 0.8rem; font-weight: 600; position: sticky; top: 0; background: #21252e; }\n.nav-list { list-style: none; padding: 0; margin: 0; }\n.nav-item { display: flex; align-items: baseline; gap: 0.5rem; padding: 0.5rem 0.8rem; cursor: pointer; border-bottom: 1px solid #232730; }\n.nav-item:hover { background: #262b35; }\n.nav-item.active { background: #2d3340; border-left: 2px solid #9dbefe; padding-left: calc(0.8rem - 2px); }\n.ni-name { flex: 1; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }\n.ni-tok { color: #9dbefe; font-family: Consolas, \"Courier New\", monospace; font-variant-numeric: tabular-nums; font-size: 0.78rem; }\n.main { flex: 1; overflow-y: auto; display: flex; flex-direction: column; min-width: 0; }\n.main-head { display: flex; align-items: baseline; gap: 1rem; padding: 0.6rem 1rem; border-bottom: 1px solid #2a2e37; flex-wrap: wrap; }\n.main-head .rt-sum { color: #8b919e; font-size: 0.82rem; flex: 0 0 60ch; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n.main-head .rt-tok { margin-left: auto; color: #9dbefe; font-family: Consolas, \"Courier New\", monospace; font-variant-numeric: tabular-nums; font-size: 0.82rem; }\n.table-wrap { flex: 1; overflow: auto; padding: 0 0.6rem 0.6rem; }\ntable.report-table { width: 100%; border-collapse: collapse; font-size: 0.8rem; }\n.report-table th { position: sticky; top: 0; background: #1a1d23; text-align: left; color: #8b919e; font-weight: 600; padding: 0.45rem 0.6rem; border-bottom: 1px solid #2a2e37; white-space: nowrap; }\n.report-table td { padding: 0.32rem 0.6rem; border-bottom: 1px solid #232730; white-space: nowrap; }\n.report-table .num { text-align: right; font-family: Consolas, \"Courier New\", monospace; font-variant-numeric: tabular-nums; color: #9dbefe; }\n.report-table .sid { font-family: Consolas, \"Courier New\", monospace; color: #c9d1d9; }\n.report-table .rt-idx { text-align: center; width: 3rem; color: #8b919e; }\n.empty { color: #8b919e; padding: 2rem; text-align: center; }\n";
